import sys
from pathlib import Path
import torch
import torch.nn as nn

_KERNEL_BUILD = Path(__file__).resolve().parent / "kernel" / "build"
if _KERNEL_BUILD.is_dir() and str(_KERNEL_BUILD) not in sys.path:
    sys.path.insert(0, str(_KERNEL_BUILD))

import benchmark_ops as _ops


class ModelNew(nn.Module):
    def __init__(self) -> None:
        super().__init__()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return _ops.relu(x)


def get_init_inputs():
    return []

#ifndef MULTIKERNELBENCH_RELU_LAUNCH_H
#define MULTIKERNELBENCH_RELU_LAUNCH_H

#include <cstdint>
#include <tuple>

#ifndef GM_ADDR
#define GM_ADDR void*
#endif

std::tuple<int64_t, int64_t, int64_t> calc_relu_tiling_params(int64_t totalLength);

extern "C" {
void launch_relu_kernel_float(GM_ADDR x, GM_ADDR y, int64_t totalLength, int64_t numBlocks, int64_t blockLength, uint32_t tileSize, void* stream);
void launch_relu_kernel_half(GM_ADDR x, GM_ADDR y, int64_t totalLength, int64_t numBlocks, int64_t blockLength, uint32_t tileSize, void* stream);
}

#define RELU_KERNEL_LAUNCH_FLOAT(x, y, len, blocks, blkLen, tileSz, stream) \
    launch_relu_kernel_float(x, y, len, blocks, blkLen, tileSz, stream)
#define RELU_KERNEL_LAUNCH_HALF(x, y, len, blocks, blkLen, tileSz, stream) \
    launch_relu_kernel_half(x, y, len, blocks, blkLen, tileSz, stream)

#endif

#include <algorithm>
#include <tuple>
#include "kernel_operator.h"
#include "platform/platform_ascendc.h"

constexpr static int64_t PIPELINE_DEPTH = 2;

template <typename T>
__global__ __aicore__ void relu_kernel(GM_ADDR x, GM_ADDR y, int64_t totalLength, int64_t blockLength, uint32_t tileSize)
{
    AscendC::TPipe pipe;
    AscendC::GlobalTensor<T> xGm, yGm;
    AscendC::TQue<AscendC::QuePosition::VECIN, PIPELINE_DEPTH> inQueueX;
    AscendC::TQue<AscendC::QuePosition::VECIN, PIPELINE_DEPTH> inQueueZero;
    AscendC::TQue<AscendC::QuePosition::VECOUT, PIPELINE_DEPTH> outQueueY;

    pipe.InitBuffer(inQueueX, PIPELINE_DEPTH, tileSize);
    pipe.InitBuffer(inQueueZero, PIPELINE_DEPTH, tileSize);
    pipe.InitBuffer(outQueueY, PIPELINE_DEPTH, tileSize);

    xGm.SetGlobalBuffer((__gm__ T *)x + blockLength * AscendC::GetBlockIdx());
    yGm.SetGlobalBuffer((__gm__ T *)y + blockLength * AscendC::GetBlockIdx());

    int64_t currentBlockLength = totalLength - AscendC::GetBlockIdx() * blockLength;
    if (currentBlockLength > blockLength) {
        currentBlockLength = blockLength;
    }

    int64_t elementNumPerTile = tileSize / sizeof(T);
    int64_t tileNum = currentBlockLength / elementNumPerTile;
    int64_t tailTileElementNum = currentBlockLength - tileNum * elementNumPerTile;

    for (int64_t i = 0; i < tileNum; ++i) {
        int64_t offset = i * elementNumPerTile;
        AscendC::DataCopyExtParams copyParams{1, static_cast<uint32_t>(elementNumPerTile * sizeof(T)), 0, 0, 0};
        AscendC::DataCopyPadExtParams<T> padParams{false, 0, 0, 0};
        auto xLocal = inQueueX.AllocTensor<T>();
        auto zeroLocal = inQueueZero.AllocTensor<T>();
        AscendC::DataCopyPad(xLocal, xGm[offset], copyParams, padParams);
        AscendC::Duplicate(zeroLocal, static_cast<T>(0), elementNumPerTile);
        inQueueX.EnQue(xLocal);
        inQueueZero.EnQue(zeroLocal);

        xLocal = inQueueX.DeQue<T>();
        zeroLocal = inQueueZero.DeQue<T>();
        auto yLocal = outQueueY.AllocTensor<T>();
        AscendC::Max(yLocal, xLocal, zeroLocal, elementNumPerTile);
        outQueueY.EnQue(yLocal);
        inQueueX.FreeTensor(xLocal);
        inQueueZero.FreeTensor(zeroLocal);

        yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopyPad(yGm[offset], yLocal, copyParams);
        outQueueY.FreeTensor(yLocal);
    }

    if (tailTileElementNum > 0) {
        int64_t offset = tileNum * elementNumPerTile;
        AscendC::DataCopyExtParams copyParams{1, static_cast<uint32_t>(tailTileElementNum * sizeof(T)), 0, 0, 0};
        AscendC::DataCopyPadExtParams<T> padParams{false, 0, 0, 0};
        auto xLocal = inQueueX.AllocTensor<T>();
        auto zeroLocal = inQueueZero.AllocTensor<T>();
        AscendC::DataCopyPad(xLocal, xGm[offset], copyParams, padParams);
        AscendC::Duplicate(zeroLocal, static_cast<T>(0), tailTileElementNum);
        inQueueX.EnQue(xLocal);
        inQueueZero.EnQue(zeroLocal);

        xLocal = inQueueX.DeQue<T>();
        zeroLocal = inQueueZero.DeQue<T>();
        auto yLocal = outQueueY.AllocTensor<T>();
        AscendC::Max(yLocal, xLocal, zeroLocal, tailTileElementNum);
        outQueueY.EnQue(yLocal);
        inQueueX.FreeTensor(xLocal);
        inQueueZero.FreeTensor(zeroLocal);

        yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopyPad(yGm[offset], yLocal, copyParams);
        outQueueY.FreeTensor(yLocal);
    }
}

std::tuple<int64_t, int64_t, int64_t> calc_relu_tiling_params(int64_t totalLength)
{
    constexpr static int64_t MIN_ELEMS_PER_CORE = 1024;
    constexpr static int64_t BUFFER_NUM = 3;
    auto ascendcPlatform = platform_ascendc::PlatformAscendCManager::GetInstance();
    uint64_t ubSize = 0;
    ascendcPlatform->GetCoreMemSize(platform_ascendc::CoreMemType::UB, ubSize);
    int64_t coreNum = ascendcPlatform->GetCoreNumAiv();
    if (coreNum <= 0) {
        coreNum = 1;
    }
    int64_t numBlocks = std::min(coreNum, (totalLength + MIN_ELEMS_PER_CORE - 1) / MIN_ELEMS_PER_CORE);
    int64_t blockLength = (totalLength + numBlocks - 1) / numBlocks;
    int64_t tileSize = ubSize / PIPELINE_DEPTH / BUFFER_NUM;
    return std::make_tuple(numBlocks, blockLength, tileSize);
}

extern "C" {

void launch_relu_kernel_float(GM_ADDR x, GM_ADDR y, int64_t totalLength, int64_t numBlocks, int64_t blockLength, uint32_t tileSize, void* stream)
{
    relu_kernel<float><<<numBlocks, nullptr, stream>>>(x, y, totalLength, blockLength, tileSize);
}

void launch_relu_kernel_half(GM_ADDR x, GM_ADDR y, int64_t totalLength, int64_t numBlocks, int64_t blockLength, uint32_t tileSize, void* stream)
{
    relu_kernel<half><<<numBlocks, nullptr, stream>>>(x, y, totalLength, blockLength, tileSize);
}

}

#include <ATen/Operators.h>
#include <torch/all.h>
#include <torch/extension.h>
#include "torch_npu/csrc/core/npu/NPUStream.h"
#include "relu_launch.h"

namespace multikernelbench_relu {

torch::Tensor relu(const torch::Tensor &x)
{
    const c10::OptionalDeviceGuard guard(x.device());
    auto y = torch::empty_like(x);
    auto stream = c10_npu::getCurrentNPUStream().stream(false);

    int64_t totalLength = x.numel();
    int64_t numBlocks = 1;
    int64_t blockLength = totalLength;
    int64_t tileSize = 0;
    std::tie(numBlocks, blockLength, tileSize) = calc_relu_tiling_params(totalLength);

    auto xPtr = reinterpret_cast<GM_ADDR>(x.data_ptr());
    auto yPtr = reinterpret_cast<GM_ADDR>(y.data_ptr());

    if (x.scalar_type() == torch::kFloat32) {
        RELU_KERNEL_LAUNCH_FLOAT(xPtr, yPtr, totalLength, numBlocks, blockLength, static_cast<uint32_t>(tileSize), stream);
    } else if (x.scalar_type() == torch::kFloat16) {
        RELU_KERNEL_LAUNCH_HALF(xPtr, yPtr, totalLength, numBlocks, blockLength, static_cast<uint32_t>(tileSize), stream);
    } else {
        TORCH_CHECK(false, "unsupported dtype for relu direct launch");
    }
    return y;
}

} // namespace multikernelbench_relu

PYBIND11_MODULE(benchmark_ops, m)
{
    m.doc() = "MultiKernelBench Ascend C direct-launch relu operator";
    m.def("relu", &multikernelbench_relu::relu, "Apply ReLU with an Ascend C direct-launch kernel");
}
